########################  main.py  ########################
import os
import uuid
import time
import boto3
from flask import Flask, request, jsonify
from selenium import webdriver
from selenium.webdriver.chrome.options import Options
from selenium.webdriver.support.ui import WebDriverWait

BUCKET = os.environ.get("SCREENSHOT_BUCKET", "")
REGION = os.environ.get("AWS_REGION", "us-east-1")
TMP_DIR = "/tmp"

app = Flask(__name__)


def _create_driver() -> webdriver.Chrome:
    chrome_options = Options()
    chrome_options.add_argument("--headless=new")
    chrome_options.add_argument("--disable-gpu")
    chrome_options.add_argument("--no-sandbox")
    chrome_options.add_argument("--disable-dev-shm-usage")
    chrome_options.add_argument("--window-size=1280,720")
    chrome_options.add_argument("--hide-scrollbars")
    chrome_options.add_experimental_option("excludeSwitches", ["enable-logging"])
    return webdriver.Chrome(options=chrome_options)


def _capture(url: str, out_file: str) -> None:
    driver = _create_driver()
    try:
        driver.get(url)
        WebDriverWait(driver, 15).until(
            lambda d: d.execute_script("return document.readyState") == "complete"
        )
        time.sleep(1)
        driver.save_screenshot(out_file)
    finally:
        driver.quit()


def _upload(local_file: str, bucket: str) -> str:
    key = f"screenshots/{os.path.basename(local_file)}"
    s3 = boto3.client("s3", region_name=REGION)
    s3.upload_file(
        local_file,
        bucket,
        key,
        ExtraArgs={"ContentType": "image/png", "ACL": "public-read"},
    )
    return f"https://{bucket}.s3.{REGION}.amazonaws.com/{key}"


@app.route("/screenshot", methods=["POST"])
def screenshot():
    body = request.get_json() or {}
    url = body.get("url", "").strip()
    if not url:
        return jsonify({"error": "url is required"}), 400
    if not url.startswith(("http://", "https://")):
        url = "http://" + url

    filename = f"{uuid.uuid4().hex}.png"
    local_path = os.path.join(TMP_DIR, filename)

    try:
        _capture(url, local_path)
        s3_url = _upload(local_path, BUCKET)
        os.remove(local_path)
        return jsonify({"screenshot_url": s3_url}), 200
    except Exception as exc:
        if os.path.exists(local_path):
            os.remove(local_path)
        return jsonify({"error": str(exc)}), 500


if __name__ == "__main__":
    app.run(host="0.0.0.0", port=8000)



